    66→void
    67→usage( void )
    68→{
    69→	fprintf( stderr, _("Issue LDAP Verify Credentials operation to verify a user's credentials\n\n"));
    70→	fprintf( stderr, _("usage: %s [options] [DN [cred]])\n"), prog);
    71→	fprintf( stderr, _("where:\n"));
    72→	fprintf( stderr, _("    DN\tDistinguished Name\n"));
    73→	fprintf( stderr, _("    cred\tCredentials (prompt if not present)\n"));
    74→	fprintf( stderr, _("options:\n"));
    75→	fprintf( stderr, _("    -a\tRequest AuthzId\n"));
    76→	fprintf( stderr, _("    -b\tRequest Password Policy Information\n"));
    77→	fprintf( stderr, _("    -E sasl=(a[utomatic]|i[nteractive]|q[uiet]>\tSASL mode (defaults to automatic if any other -E option provided, otherwise none))\n"));
    78→	fprintf( stderr, _("    -E mech=<mech>\tSASL mechanism (default "" e.g. Simple)\n"));
    79→	fprintf( stderr, _("    -E realm=<realm>\tSASL Realm (defaults to none)\n"));
    80→	fprintf( stderr, _("    -E authcid=<authcid>\tSASL Authentication Identity (defaults to USER)\n"));
    81→	fprintf( stderr, _("    -E authzid=<authzid>\tSASL Authorization Identity (defaults to none)\n"));
    82→	fprintf( stderr, _("    -E secprops=<secprops>\tSASL Security Properties (defaults to none)\n"));
    83→	tool_common_usage();
    84→	exit( EXIT_FAILURE );
    85→}
    86→
    87→
    88→const char options[] = "abE:"
    89→	"d:D:e:h:H:InNO:o:p:QR:U:vVw:WxX:y:Y:Z";
    90→
    91→int
    92→handle_private_option( int i )
    93→{
    94→	switch ( i ) {
    95→		char	*control, *cvalue;
    96→	case 'E': /* vc extension */
    97→		if( protocol == LDAP_VERSION2 ) {
    98→			fprintf( stderr, _("%s: -E incompatible with LDAPv%d\n"),
    99→				prog, protocol );
   100→			exit( EXIT_FAILURE );
   101→		}
   102→
   103→		/* should be extended to support comma separated list of
   104→		 *	[!]key[=value] parameters, e.g.  -E !foo,bar=567
   105→		 */
   106→
   107→		cvalue = NULL;
   108→		if( optarg[0] == '!' ) {
   109→			optarg++;
   110→		}
   111→
   112→		control = optarg;
   113→		if ( (cvalue = strchr( control, '=' )) != NULL ) {
   114→			*cvalue++ = '\0';
   115→		}
   116→
   117→		if (strcasecmp(control, "sasl") == 0) {
   118→#if defined(LDAP_API_FEATURES_VERIFY_CREDENTIALS_INTERACTIVE) && defined(HAVE_CYRUS_SASL)
   119→			if (vc_sasl != LDAP_SASL_NONE) {
   120→				fprintf(stderr,
   121→				    _("SASL option previously specified\n"));
   122→				exit(EXIT_FAILURE);
   123→			}
   124→			if (cvalue == NULL) {
   125→				fprintf(stderr,
   126→					_("missing mode in SASL option\n"));
   127→				exit(EXIT_FAILURE);
   128→			}
   129→
   130→			switch (*cvalue) {
   131→			case 'a':
   132→			case 'A':
   133→				vc_sasl = LDAP_SASL_AUTOMATIC;
   134→				break;
   135→			case 'i':
   136→			case 'I':
   137→				vc_sasl = LDAP_SASL_INTERACTIVE;
   138→				break;
   139→			case 'q':
   140→			case 'Q':
   141→				vc_sasl = LDAP_SASL_QUIET;
   142→				break;
   143→			default:
   144→				fprintf(stderr,
   145→					_("unknown mode %s in SASL option\n"), cvalue);
   146→				exit(EXIT_FAILURE);
   147→			}
   148→#else
   149→			fprintf(stderr,
   150→				_("%s: not compiled with SASL support\n"), prog);
   151→			exit(EXIT_FAILURE);
   152→#endif
   153→
   154→		} else if (strcasecmp(control, "mech") == 0) {
   155→#if defined(LDAP_API_FEATURES_VERIFY_CREDENTIALS_INTERACTIVE) && defined(HAVE_CYRUS_SASL)
   156→			if (vc_sasl_mech) {
   157→				fprintf(stderr,
   158→				    _("SASL mech previously specified\n"));
   159→				exit(EXIT_FAILURE);
   160→			}
   161→			if (cvalue == NULL) {
   162→				fprintf(stderr,
   163→					_("missing mech in SASL option\n"));
   164→				exit(EXIT_FAILURE);
   165→			}
   166→
   167→			vc_sasl_mech = ber_strdup(cvalue);
   168→#else
   169→#endif
   170→
   171→		} else if (strcasecmp(control, "realm") == 0) {
   172→#if defined(LDAP_API_FEATURES_VERIFY_CREDENTIALS_INTERACTIVE) && defined(HAVE_CYRUS_SASL)
   173→			if (vc_sasl_realm) {
   174→				fprintf(stderr,
   175→				    _("SASL realm previously specified\n"));
   176→				exit(EXIT_FAILURE);
   177→			}
   178→			if (cvalue == NULL) {
   179→				fprintf(stderr,
   180→					_("missing realm in SASL option\n"));
   181→				exit(EXIT_FAILURE);
   182→			}
   183→
   184→			vc_sasl_realm = ber_strdup(cvalue);
   185→#else
   186→			fprintf(stderr,
   187→				_("%s: not compiled with SASL support\n"), prog);
   188→			exit(EXIT_FAILURE);
   189→#endif
   190→
   191→		} else if (strcasecmp(control, "authcid") == 0) {
   192→#if defined(LDAP_API_FEATURES_VERIFY_CREDENTIALS_INTERACTIVE) && defined(HAVE_CYRUS_SASL)
   193→			if (vc_sasl_authcid) {
   194→				fprintf(stderr,
   195→				    _("SASL authcid previously specified\n"));
   196→				exit(EXIT_FAILURE);
   197→			}
   198→			if (cvalue == NULL) {
   199→				fprintf(stderr,
   200→					_("missing authcid in SASL option\n"));
   201→				exit(EXIT_FAILURE);
   202→			}
   203→
   204→			vc_sasl_authcid = ber_strdup(cvalue);
   205→#else
   206→			fprintf(stderr,
   207→				_("%s: not compiled with SASL support\n"), prog);
   208→			exit(EXIT_FAILURE);
   209→#endif
   210→
   211→		} else if (strcasecmp(control, "authzid") == 0) {
   212→#if defined(LDAP_API_FEATURES_VERIFY_CREDENTIALS_INTERACTIVE) && defined(HAVE_CYRUS_SASL)
   213→			if (vc_sasl_authzid) {
   214→				fprintf(stderr,
   215→				    _("SASL authzid previously specified\n"));
   216→				exit(EXIT_FAILURE);
   217→			}
   218→			if (cvalue == NULL) {
   219→				fprintf(stderr,
   220→					_("missing authzid in SASL option\n"));
   221→				exit(EXIT_FAILURE);
   222→			}
   223→
   224→			vc_sasl_authzid = ber_strdup(cvalue);
   225→#else
   226→			fprintf(stderr,
   227→				_("%s: not compiled with SASL support\n"), prog);
   228→			exit(EXIT_FAILURE);
   229→#endif
   230→
   231→		} else if (strcasecmp(control, "secprops") == 0) {
   232→#if defined(LDAP_API_FEATURES_VERIFY_CREDENTIALS_INTERACTIVE) && defined(HAVE_CYRUS_SASL)
   233→			if (vc_sasl_secprops) {
   234→				fprintf(stderr,
   235→				    _("SASL secprops previously specified\n"));
   236→				exit(EXIT_FAILURE);
   237→			}
   238→			if (cvalue == NULL) {
   239→				fprintf(stderr,
   240→					_("missing secprops in SASL option\n"));
   241→				exit(EXIT_FAILURE);
   242→			}
   243→
   244→			vc_sasl_secprops = ber_strdup(cvalue);
   245→#else
   246→			fprintf(stderr,
   247→				_("%s: not compiled with SASL support\n"), prog);
   248→			exit(EXIT_FAILURE);
   249→#endif
   250→
   251→		} else {
   252→		    fprintf( stderr, _("Invalid Verify Credentials extension name: %s\n"), control );
   253→		    usage();
   254→		}
   255→		break;
   256→
   257→	case 'a':  /* request authzid */
   258→		req_authzid++;
   259→		break;
   260→
   261→	case 'b':  /* request authzid */
   262→		req_pp++;
   263→		break;
   264→
   265→	default:
   266→		return 0;
   267→	}
   268→	return 1;
   269→}
