   272→int
   273→main( int argc, char *argv[] )
   274→{
   275→	int		rc;
   276→	LDAP		*ld = NULL;
   277→	char		*matcheddn = NULL, *text = NULL, **refs = NULL;
   278→	int rcode;
   279→	char * diag = NULL;
   280→	struct berval	*scookie = NULL;
   281→	struct berval	*scred = NULL;
   282→	int		id, code = 0;
   283→	LDAPMessage	*res;
   284→	LDAPControl	**ctrls = NULL;
   285→	LDAPControl	**vcctrls = NULL;
   286→	int nvcctrls = 0;
   287→
   288→	tool_init( TOOL_VC );
   289→	prog = lutil_progname( "ldapvc", argc, argv );
   290→
   291→	/* LDAPv3 only */
   292→	protocol = LDAP_VERSION3;
   293→
   294→	tool_args( argc, argv );
   295→
   296→	if (argc - optind > 0) {
   297→		dn = argv[optind++];
   298→	}
   299→	if (argc - optind > 0) {
   300→		cred.bv_val = strdup(argv[optind++]);
   301→		cred.bv_len = strlen(cred.bv_val);
   302→	}
   303→	if (argc - optind > 0) {
   304→		usage();
   305→	}
   306→	if (dn 
   307→#ifdef LDAP_API_FEATURE_VERIFY_CREDENTIALS_INTERACTIVE
   308→           && !vc_sasl_mech 
   309→#endif
   310→           && !cred.bv_val)
   311→	{
   312→		cred.bv_val = strdup(getpassphrase(_("User's password: ")));
   313→	    cred.bv_len = strlen(cred.bv_val);
   314→	}
   315→
   316→#ifdef LDAP_API_FEATURE_VERIFY_CREDENTIALS_INTERACTIVE
   317→    if (vc_sasl_mech && (vc_sasl == LDAP_SASL_NONE)) {
   318→		vc_sasl = LDAP_SASL_AUTOMATIC;
   319→	}
   320→#endif
   321→
   322→	ld = tool_conn_setup( 0, 0 );
   323→
   324→	tool_bind( ld );
   325→
   326→	if ( dont ) {
   327→		rc = LDAP_SUCCESS;
   328→		goto skip;
   329→	}
   330→
   331→	tool_server_controls( ld, NULL, 0 );
   332→
   333→    if (req_authzid) {
   334→		vcctrls = (LDAPControl **) malloc(3*sizeof(LDAPControl *));
   335→		vcctrls[nvcctrls] = (LDAPControl *) malloc(sizeof(LDAPControl));
   336→		vcctrls[nvcctrls]->ldctl_oid = ldap_strdup(LDAP_CONTROL_AUTHZID_REQUEST);
   337→		vcctrls[nvcctrls]->ldctl_iscritical = 0;
   338→		vcctrls[nvcctrls]->ldctl_value.bv_val = NULL;
   339→		vcctrls[nvcctrls]->ldctl_value.bv_len = 0;
   340→		vcctrls[++nvcctrls] = NULL;
   341→    }
   342→
   343→    if (req_pp) {
   344→		if (!vcctrls) vcctrls = (LDAPControl **) malloc(3*sizeof(LDAPControl *));
   345→		vcctrls[nvcctrls] = (LDAPControl *) malloc(sizeof(LDAPControl));
   346→		vcctrls[nvcctrls]->ldctl_oid = ldap_strdup(LDAP_CONTROL_PASSWORDPOLICYREQUEST);
   347→		vcctrls[nvcctrls]->ldctl_iscritical = 0;
   348→		vcctrls[nvcctrls]->ldctl_value.bv_val = NULL;
   349→		vcctrls[nvcctrls]->ldctl_value.bv_len = 0;
   350→		vcctrls[++nvcctrls] = NULL;
   351→    }
   352→
   353→#ifdef LDAP_API_FEATURE_VERIFY_CREDENTIALS_INTERACTIVE
   354→#ifdef HAVE_CYRUS_SASL
   355→    if (vc_sasl_mech) {
   356→		int msgid;
   357→		void * defaults;
   358→		void * context = NULL;
   359→		const char *rmech = NULL;
   360→
   361→		defaults = lutil_sasl_defaults(ld,
   362→			vc_sasl_mech,
   363→			vc_sasl_realm,
   364→			vc_sasl_authcid,
   365→			cred.bv_val,
   366→			sasl_authz_id);
   367→
   368→		do {
   369→			rc = ldap_verify_credentials_interactive(ld, dn, vc_sasl_mech,
   370→				vcctrls, NULL, NULL,
   371→				vc_sasl, lutil_sasl_interact, defaults, context,
   372→				res, &rmech, &msgid); 
   373→
   374→			if (rc != LDAP_SASL_BIND_IN_PROGRESS) break;
   375→
   376→			ldap_msgfree(res);
   377→
   378→			if (ldap_result(ld, msgid, LDAP_MSG_ALL, NULL, &res) == -1 || !res) {
   379→				ldap_get_option(ld, LDAP_OPT_RESULT_CODE, (void*) &rc);
   380→				ldap_get_option(ld, LDAP_OPT_DIAGNOSTIC_MESSAGE, (void*) &text);
   381→				tool_perror( "ldap_verify_credentials_interactive", rc, NULL, NULL, text, NULL);
   382→				ldap_memfree(text);
   383→				tool_exit(ld, rc);
   384→			}
   385→		} while (rc == LDAP_SASL_BIND_IN_PROGRESS);
   386→
   387→	    lutil_sasl_freedefs(defaults);
   388→
   389→	    if( rc != LDAP_SUCCESS ) {
   390→			ldap_get_option(ld, LDAP_OPT_DIAGNOSTIC_MESSAGE, (void*) &text);
   391→		    tool_perror( "ldap_verify_credentials", rc, NULL, NULL, text, NULL );
   392→		    rc = EXIT_FAILURE;
   393→		    goto skip;
   394→	    }
   395→
   396→	} else
   397→#endif
   398→#endif
   399→    {
   400→	    rc = ldap_verify_credentials( ld,
   401→		    NULL,
   402→		    dn, NULL, cred.bv_val ? &cred: NULL, vcctrls,
   403→		    NULL, NULL, &id ); 
   404→    
   405→	    if( rc != LDAP_SUCCESS ) {
   406→			ldap_get_option(ld, LDAP_OPT_DIAGNOSTIC_MESSAGE, (void*) &text);
   407→		    tool_perror( "ldap_verify_credentials", rc, NULL, NULL, text, NULL );
   408→		    rc = EXIT_FAILURE;
   409→		    goto skip;
   410→	    }
   411→
   412→	    for ( ; ; ) {
   413→		    struct timeval	tv;
   414→
   415→		    if ( tool_check_abandon( ld, id ) ) {
   416→			    tool_exit( ld, LDAP_CANCELLED );
   417→		    }
   418→
   419→		    tv.tv_sec = 0;
   420→		    tv.tv_usec = 100000;
   421→
   422→		    rc = ldap_result( ld, LDAP_RES_ANY, LDAP_MSG_ALL, &tv, &res );
   423→		    if ( rc < 0 ) {
   424→			    tool_perror( "ldap_result", rc, NULL, NULL, NULL, NULL );
   425→			    tool_exit( ld, rc );
   426→		    }
   427→
   428→		    if ( rc != 0 ) {
   429→			    break;
   430→		    }
   431→	    }
   432→	}
   433→
   434→	ldap_controls_free(vcctrls);
   435→	vcctrls = NULL;
   436→
   437→	rc = ldap_parse_result( ld, res,
   438→		&code, &matcheddn, &text, &refs, &ctrls, 0 );
   439→
   440→	if (rc == LDAP_SUCCESS) rc = code;
   441→
   442→	if (rc != LDAP_SUCCESS) {
   443→		tool_perror( "ldap_parse_result", rc, NULL, matcheddn, text, refs );
   444→		rc = EXIT_FAILURE;
   445→		goto skip;
   446→	}
   447→
   448→	rc = ldap_parse_verify_credentials( ld, res, &rcode, &diag, &scookie, &scred, &vcctrls );
   449→	ldap_msgfree(res);
   450→
   451→	if (rc != LDAP_SUCCESS) {
   452→		tool_perror( "ldap_parse_verify_credentials", rc, NULL, NULL, NULL, NULL );
   453→		rc = EXIT_FAILURE;
   454→		goto skip;
   455→	}
   456→
   457→	if (rcode != LDAP_SUCCESS) {
   458→		printf(_("Failed: %s (%d)\n"), ldap_err2string(rcode), rcode);
   459→	}
   460→
   461→	if (diag && *diag) {
   462→	    printf(_("Diagnostic: %s\n"), diag);
   463→	}
   464→
   465→	if (vcctrls) {
   466→		tool_print_ctrls( ld, vcctrls );
   467→	}
   468→
   469→skip:
   470→	if ( verbose || code != LDAP_SUCCESS ||
   471→		( matcheddn && *matcheddn ) || ( text && *text ) || refs || ctrls )
   472→	{
   473→		printf( _("Result: %s (%d)\n"), ldap_err2string( code ), code );
   474→
   475→		if( text && *text ) {
   476→			printf( _("Additional info: %s\n"), text );
   477→		}
   478→
   479→		if( matcheddn && *matcheddn ) {
   480→			printf( _("Matched DN: %s\n"), matcheddn );
   481→		}
   482→
   483→		if( refs ) {
   484→			int i;
   485→			for( i=0; refs[i]; i++ ) {
   486→				printf(_("Referral: %s\n"), refs[i] );
   487→			}
   488→		}
   489→
   490→		if (ctrls) {
   491→			tool_print_ctrls( ld, ctrls );
   492→			ldap_controls_free( ctrls );
   493→		}
   494→	}
   495→
   496→	ber_memfree( text );
   497→	ber_memfree( matcheddn );
   498→	ber_memvfree( (void **) refs );
   499→	ber_bvfree( scookie );
   500→	ber_bvfree( scred );
   501→	ber_memfree( diag );
   502→	free( cred.bv_val );
   503→
   504→	/* disconnect from server */
   505→	tool_exit( ld, code == LDAP_SUCCESS ? EXIT_SUCCESS : EXIT_FAILURE );
   506→}
